from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Convert a list of triples about a city (or related entities) into a single fluent sentence."""
    if not triples:
        return ""

    # Identify the main subject - prefer city-like subjects (those with commas indicating city, state format)
    subject_counts = {}
    for t in triples:
        subject_counts[t.subject] = subject_counts.get(t.subject, 0) + 1

    # Prioritize subjects that appear to be cities (contain commas, indicating "City, State" format)
    city_subjects = [s for s in subject_counts.keys() if ',' in s]
    if city_subjects:
        main_subject = city_subjects[0]
    else:
        # Fallback to most frequent subject, but prefer non-country entities
        country_keywords = ['United States', 'Canada', 'Mexico', 'United Kingdom', 'Germany', 'France']
        non_country_subjects = [s for s in subject_counts.keys() if not any(k in s for k in country_keywords)]
        if non_country_subjects:
            main_subject = max(non_country_subjects, key=lambda x: subject_counts.get(x, 0))
        else:
            main_subject = max(subject_counts.keys(), key=lambda x: subject_counts.get(x, 0))

    # Group triples by subject
    main_triples = [t for t in triples if t.subject == main_subject]
    other_triples = [t for t in triples if t.subject != main_subject]

    # Build sentence parts with proper connectors
    sentence_parts = []

    # Start with subject and type
    type_obj = next((t.object for t in triples if t.predicate == "type"), None)
    if type_obj:
        sentence_parts.append(f"{main_subject}, a {type_obj}")
    else:
        sentence_parts.append(main_subject)

    # Collect location information - build proper hierarchy
    country = next((t.object for t in main_triples if t.predicate == "country"), None)
    state = next((t.object for t in main_triples if t.predicate == "state"), None)
    is_part_of = next((t.object for t in main_triples if t.predicate == "isPartOf"), None)

    # Also check for state in other_triples if not found in main_triples
    if not state:
        state = next((t.object for t in other_triples if t.predicate == "state"), None)

    location_parts = []
    if country:
        location_parts.append(f"in {country}")
    if state:
        location_parts.append(f"in the state of {state}")
    if is_part_of:
        location_parts.append(f"and is part of {is_part_of}")

    if location_parts:
        sentence_parts.append(", ".join(location_parts))

    # Collect city attributes
    attrs = []
    population = next((t.object for t in triples if t.predicate == "populationTotal"), None)
    if population:
        attrs.append(f"a population of {population}")

    metro_pop = next((t.object for t in triples if t.predicate == "populationMetro"), None)
    if metro_pop:
        attrs.append(f"metro population of {metro_pop}")

    density = next((t.object for t in triples if t.predicate == "populationDensity"), None)
    if density:
        attrs.append(f"population density of {density}")

    area = next((t.object for t in triples if t.predicate == "areaTotal"), None)
    land_area = next((t.object for t in triples if t.predicate == "areaOfLand"), None)
    water_area = next((t.object for t in triples if t.predicate == "areaOfWater"), None)
    if area:
        attrs.append(f"area of {area}")
    if land_area:
        attrs.append(f"land area of {land_area}")
    if water_area:
        attrs.append(f"water area of {water_area}")

    elevation = next((t.object for t in triples if t.predicate == "elevationAboveTheSeaLevel"), None)
    if elevation:
        attrs.append(f"elevation of {elevation} meters above sea level")

    timezone = next((t.object for t in triples if t.predicate == "timeZone"), None)
    utc_offset = next((t.object for t in triples if t.predicate == "utcOffset"), None)
    if timezone:
        attrs.append(f"time zone {timezone}")
    if utc_offset:
        attrs.append(f"UTC offset {utc_offset}")

    area_codes = next((t.object for t in triples if t.predicate == "areaCode"), None)
    postal_codes = next((t.object for t in triples if t.predicate == "postalCode"), None)
    if area_codes:
        attrs.append(f"area codes {area_codes}")
    if postal_codes:
        attrs.append(f"postal codes {postal_codes}")

    leader = next((t.object for t in triples if t.predicate == "leader"), None)
    leader_title = next((t.object for t in triples if t.predicate == "leaderTitle"), None)
    if leader and leader_title:
        attrs.append(f"{leader_title} {leader}")
    elif leader:
        attrs.append(f"led by {leader}")
    if leader_title:
        attrs.append(f"with leader title {leader_title}")

    gov_type = next((t.object for t in triples if t.predicate == "governmentType"), None)
    if gov_type:
        attrs.append(f"{gov_type}")

    largest_city = next((t.object for t in triples if t.predicate == "largestCity"), None)
    if largest_city:
        attrs.append(f"largest city is {largest_city}")

    county_seat = next((t.object for t in triples if t.predicate == "countySeat"), None)
    if county_seat:
        attrs.append(f"county seat is {county_seat}")

    if attrs:
        sentence_parts.append("with " + ", ".join(attrs))

    # Collect additional information from all triples (including related entities)
    additional_info = []
    for t in other_triples:
        if t.predicate == "capital":
            additional_info.append(f"the capital is {t.object}")
        elif t.predicate == "language":
            additional_info.append(f"languages include {t.object}")
        elif t.predicate == "ethnicGroup":
            additional_info.append(f"ethnic groups include {t.object}")
        elif t.predicate == "demonym":
            additional_info.append(f"demonym is {t.object}")
        elif t.predicate == "leaderTitle":
            additional_info.append(f"the leader title is {t.object}")
        elif t.predicate == "demonym":
            additional_info.append(f"residents are known as {t.object}")

    if additional_info:
        sentence_parts.append(f", with " + ", ".join(additional_info))

    # Join all parts into a coherent sentence
    result = ", ".join(sentence_parts)
    if not result.endswith("."):
        result += "."

    return result

# EVOLVE-BLOCK-END
